gpio_led_test.c<pre><code>#include &lt;stdio.h&gt;
#include &lt;stdlib.h&gt;
#include &lt;unistd.h&gt;
#include &lt;fcntl.h&gt;
#include &lt;string.h&gt;
#include &lt;errno.h&gt;
#include &lt;linux/gpio.h&gt;
#include &lt;sys/ioctl.h&gt;

#define GPIO_CHIP "/dev/gpiochip4"
#define NUM_LEDS  6

int main() {
    int chip_fd;
    struct gpiohandle_request req;
    struct gpiohandle_data data;
    int gpio_lines[NUM_LEDS] = {22, 23, 24, 25, 26, 27};

    chip_fd = open(GPIO_CHIP, O_RDONLY);
    if (chip_fd &lt; 0) {
        fprintf(stderr, "Failed to open %s: %s\n",
                GPIO_CHIP, strerror(errno));
        return 1;
    }

    memset(&amp;req, 0, sizeof(req));
    for (int i = 0; i &lt; NUM_LEDS; i++)
        req.lineoffsets[i] = gpio_lines[i];
    req.lines = NUM_LEDS;
    req.flags = GPIOHANDLE_REQUEST_OUTPUT;
    strcpy(req.consumer_label, "led_test");

    if (ioctl(chip_fd, GPIO_GET_LINEHANDLE_IOCTL, &amp;req) &lt; 0) {
        fprintf(stderr, "Failed to get line handle: %s\n",
                strerror(errno));
        close(chip_fd);
        return 1;
    }

    /* All ON */
    memset(&amp;data, 1, sizeof(data));
    ioctl(req.fd, GPIOHANDLE_SET_LINE_VALUES_IOCTL, &amp;data);
    sleep(2);

    /* One by one ON */
    memset(&amp;data, 0, sizeof(data));
    for (int i = 0; i &lt; NUM_LEDS; i++) {
        data.values[i] = 1;
        ioctl(req.fd, GPIOHANDLE_SET_LINE_VALUES_IOCTL, &amp;data);
        usleep(400000);
    }

    /* Blink 5 times */
    for (int b = 0; b &lt; 5; b++) {
        memset(&amp;data, 1, sizeof(data));
        ioctl(req.fd, GPIOHANDLE_SET_LINE_VALUES_IOCTL, &amp;data);
        usleep(300000);
        memset(&amp;data, 0, sizeof(data));
        ioctl(req.fd, GPIOHANDLE_SET_LINE_VALUES_IOCTL, &amp;data);
        usleep(300000);
    }

    close(req.fd);
    close(chip_fd);
    return 0;
}
